#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k04629Custom {
public:
    __aicore__ inline KernelCa6k04629Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t groups, uint32_t C,
                                uint32_t totalRows) {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        groups_ = groups;
        C_ = C;
        totalRows_ = totalRows;
        chunk_ = C_ / groups_;
        rowLen_ = C_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process() {
        if (totalRows_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        uint32_t baseRow = blockIdx * (tileLen_ / rowLen_);
        while (baseRow < totalRows_) {
            uint32_t curRows = tileLen_ / rowLen_;
            if (baseRow + curRows > totalRows_) {
                curRows = totalRows_ - baseRow;
            }
            uint32_t curLen = curRows * rowLen_;

            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[baseRow * rowLen_], curLen);
            inQueueX_.EnQue(xLocal);

            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();
            xLocal = inQueueX_.DeQue<float>();

            for (uint32_t r = 0; r < curRows; r++) {
                uint32_t rowBase = r * rowLen_;
                for (uint32_t g = 0; g < groups_; g++) {
                    for (uint32_t j = 0; j < chunk_; j++) {
                        float val = xLocal[rowBase + g * chunk_ + j];
                        yLocal[rowBase + j * groups_ + g] = val;
                    }
                }
            }

            tmpQueue_.FreeTensor(tLocal);
            outQueueY_.EnQue<float>(yLocal);
            inQueueX_.FreeTensor(xLocal);

            yLocal = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[baseRow * rowLen_], yLocal, curLen);
            outQueueY_.FreeTensor(yLocal);

            baseRow += blockNum * (tileLen_ / rowLen_);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_;
    uint32_t tileLen_;
    uint32_t groups_;
    uint32_t C_;
    uint32_t totalRows_;
    uint32_t chunk_;
    uint32_t rowLen_;
};

extern "C" __global__ __aicore__ void ca6k_04629_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k04629Custom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.groups, tiling_data.C, tiling_data.totalRows);
    op.Process();
}
